/**
 * EXIF-thumbnail fast-path bench.
 *
 * Compares three paths on the same 1280×720 source image that carries a
 * 160×120 EXIF APP1 thumbnail (generated by `scripts/gen-exif-fixture.mjs`):
 *
 *   1. extractExifThumbnail(bytes)             — just the APP1 parse.
 *   2. end-to-end getPalette(thumbnailExtractor) — full pipeline via the
 *                                                  embedded thumbnail.
 *   3. end-to-end getPalette(DC-only)           — same result, main image.
 *   4. end-to-end getPalette(full-decode)       — reference.
 *
 * When the fast path is used, the thumbnail is a ~2 KB JPEG that jSquash
 * decodes at trivial cost; the resize + histogram cost drops to noise.
 */

import { readFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { bench, describe } from "vitest";
import { decodeJpegDcOnly, getPalette, initWasm } from "@ken0106/core";
import { extractExifThumbnail } from "@ken0106/exif";

const PALETA_WASM = fileURLToPath(
  new URL("../packages/core/wasm/paleta_core_bg.wasm", import.meta.url),
);
await initWasm(await readFile(PALETA_WASM));

const MOZJPEG_WASM = fileURLToPath(
  new URL(
    "../node_modules/.pnpm/@jsquash+jpeg@1.6.0/node_modules/@jsquash/jpeg/codec/dec/mozjpeg_dec.wasm",
    import.meta.url,
  ),
);
const jsquash = (await import("@jsquash/jpeg/decode")) as unknown as {
  default: (buffer: ArrayBuffer) => Promise<{ data: Uint8ClampedArray; width: number; height: number }>;
  init: (module: WebAssembly.Module) => Promise<void>;
};
await jsquash.init(await WebAssembly.compile(await readFile(MOZJPEG_WASM)));

async function loadFixture(name: string): Promise<Uint8Array> {
  return new Uint8Array(await readFile(fileURLToPath(new URL(`../test/fixtures/${name}`, import.meta.url))));
}

const withThumb = await loadFixture("paleta-scene-with-exif-thumb.jpg");
const scene = await loadFixture("paleta-scene-large-420.jpg");

const jsquashDecoder = async (bytes: Uint8Array) => {
  const buf =
    bytes.byteOffset === 0 && bytes.byteLength === bytes.buffer.byteLength
      ? (bytes.buffer as ArrayBuffer)
      : (bytes.slice().buffer as ArrayBuffer);
  const img = await jsquash.default(buf);
  return {
    data: new Uint8Array(img.data.buffer, img.data.byteOffset, img.data.byteLength),
    width: img.width,
    height: img.height,
  };
};

describe("EXIF APP1 parse only", () => {
  bench("extractExifThumbnail (1280×720 + 160×120 thumb)", () => {
    extractExifThumbnail(withThumb);
  });
});

describe("end-to-end getPalette on 1280×720 scene", () => {
  bench("EXIF-thumb fast path (extractor + jSquash on 160×120 thumb)", async () => {
    await getPalette(withThumb, {
      decoder: jsquashDecoder,
      thumbnailExtractor: extractExifThumbnail,
      colorCount: 8,
    });
  });

  bench("DC-only path (Rust WASM on main image)", async () => {
    await getPalette(withThumb, {
      decoder: jsquashDecoder,
      useDcOnlyJpeg: true,
      colorCount: 8,
    });
  });

  bench("full-decode path (jSquash + resize on main image)", async () => {
    await getPalette(scene, {
      decoder: jsquashDecoder,
      colorCount: 8,
    });
  });
});

// Keep a reference so tree-shaking can't eliminate the import even if
// someone later guards the describe blocks.
void decodeJpegDcOnly;
